actions.script:
java.util.Calendar cal = java.util.Calendar.getInstance();
cal.setTime(startDate);
int added = 0;
while (added < daysToAdd) {
    cal.add(java.util.Calendar.DATE, 1);
    int dayOfWeek = cal.get(java.util.Calendar.DAY_OF_WEEK);
    if (dayOfWeek != java.util.Calendar.SATURDAY && dayOfWeek != java.util.Calendar.SUNDAY) {
        // Check for holiday
        java.sql.Date current = new java.sql.Date(cal.getTimeInMillis());
        def holiday = ec.entity.find("trade.PublicHoliday").condition("holidayDate", current).one();
        if (!holiday) {
            added++;
        } else {
            ec.logger.info("Skipping holiday: ${current}");
        }
    }
}
resultDate = new java.sql.Date(cal.getTimeInMillis());

def resultMap = tx.getMap()
def instMap = inst?.getMap() ?: [:]

if (inst?.instrumentTypeEnumId == 'IMPORT_LC') {
    // Fetch full LC details (includes validation aliases and fields)
    def lcDetails = ec.service.sync().name("trade.importlc.ImportLcServices.get#ImportLetterOfCredit")
        .parameter("instrumentId", tx.instrumentId).call()
    if (lcDetails) {
        // Merge LC details into instrument map (excluding parties which we handle separately)
        def lcData = new HashMap(lcDetails)
        lcData.remove("parties")
        instMap.putAll(lcData)

        // Add parties list for BIC resolution
        instMap.parties = lcDetails.parties
    }
}

context.putAll(resultMap)
context.instrument = instMap

if.script:
if (partyName && !(partyName ==~ /^[A-Z a-z0-9 \/\-\?\:\(\)\.,'\+]*$/)) {
    ec.message.addError("Party Name contains invalid SWIFT characters. Only A-Z, 0-9, space, / - ? : ( ) . , ' + are allowed.")
}
